def fib(n):
    if n <= 1:  # runs when n is NOT <= 1 (i.e., n > 1)
        return n
    else:  # runs when n IS <= 1
        return fib(n-1) + fib(n-2)

for i in range(7):  # Loop from 0 to 6
    print(i, fib(i))
```

